Codex CLI 啟動：# Codex · R119e · todo.html 加完成率 Donut + 剩餘天數 ETA · Wallpaper tier

## 背景

用戶 7 天出國 · 希望**每日從 iPhone 看** todo 完成度 + 預估幾天到 100% · 而且風格要 **時尚大膽高級**（自己看用）。

R109 已鎖 69 + R118 Q+O 20 + 可能 R119 補 · ~90 items · 每條有 Est h · status（ship-before/beta+1/backlog · 完成 / 未完）。

## 風格指南（用戶偏好）

**R88 palette**（已定）：bone `#E7E0D6` · ink `#0B120E` · charcoal `#2F3232` · iron `#838585` · tangerine CTA `#EC662D` · hot `#FC6D2B` · warning `#F0A145` · positive `#EF7D2F` · negative `#3C3C3C`

**視覺參考 tier**：Wallpaper / Kinfolk / Apple Store / Stripe / **Linear**

**字體**：`Source Han Serif TC` headline · `Source Han Sans TC` body · `Source Serif 4` numbers（R115 確定）

**禁**：childish 色 · 政府公文感 · Bootstrap 預設 · 彩虹圖表

## 你要做

### A. 建 `docs/portfolio-spec-report/progress.json`（Codex 之後每 ship 一條會更新）

```json
{
  "lastUpdatedAt": "2026-04-18T18:00:00Z",
  "totalItems": 89,
  "totalEstHours": 450,
  "byStatus": {
    "shipBefore": { "total": 30, "done": 0, "totalEstHours": 185, "doneEstHours": 0 },
    "beta1": { "total": 20, "done": 0, "totalEstHours": 142, "doneEstHours": 0 },
    "backlog": { "total": 19, "done": 0, "totalEstHours": 123, "doneEstHours": 0 },
    "qa": { "total": 12, "done": 0, "totalEstHours": 60 },
    "ops": { "total": 8, "done": 0, "totalEstHours": 32 }
  },
  "completionPct": 0.0,
  "etaDaysToShipBefore": 22,
  "etaDaysToFullProduct": 55,
  "velocityHoursPerDay": 8,
  "items": [
    { "id": "T01", "title": "Morning Note Dashboard deep-link", "estH": 6, "done": false, "completedAt": null },
    ... 89 entries
  ]
}
```

每條 T / Q / O item 一個 entry · done=false 初始。

### B. 建 `docs/portfolio-spec-report/progress.js`（前端讀 json → 算 + render）

```js
// Pure browser JS · 無外部 lib
export async function renderProgress(containerEl) {
  const res = await fetch('./progress.json?v=' + Date.now())
  const data = await res.json()
  const pct = data.completionPct || 0
  const etaDays = data.etaDaysToShipBefore || 0

  containerEl.innerHTML = `
    <div class="progress-wrap">
      ${renderDonut(pct)}
      ${renderEtaBadge(etaDays)}
      ${renderBreakdown(data.byStatus)}
      ${renderVelocityNote(data.velocityHoursPerDay, data.lastUpdatedAt)}
    </div>
  `
}

function renderDonut(pct) {
  const size = 380
  const stroke = 32
  const r = (size - stroke) / 2
  const circ = 2 * Math.PI * r
  const off = circ * (1 - pct / 100)
  return `
    <svg class="donut" width="${size}" height="${size}" viewBox="0 0 ${size} ${size}">
      <circle cx="${size/2}" cy="${size/2}" r="${r}" 
        stroke="var(--bone-deep)" stroke-width="${stroke}" fill="none"/>
      <circle cx="${size/2}" cy="${size/2}" r="${r}"
        stroke="var(--cta)" stroke-width="${stroke}" fill="none"
        stroke-dasharray="${circ}" stroke-dashoffset="${off}"
        stroke-linecap="round"
        transform="rotate(-90 ${size/2} ${size/2})"
        style="transition: stroke-dashoffset 1.8s cubic-bezier(.22,.94,.37,1);"/>
      <text x="${size/2}" y="${size/2 - 8}" text-anchor="middle" 
        class="donut-pct">${pct.toFixed(1)}%</text>
      <text x="${size/2}" y="${size/2 + 30}" text-anchor="middle" 
        class="donut-sub">Ship-Before 進度</text>
    </svg>
  `
}

function renderEtaBadge(etaDays) {
  return `
    <div class="eta">
      <div class="eta-label">距離 ship-before 完成</div>
      <div class="eta-days"><span class="num">${etaDays}</span> <span class="unit">天</span></div>
      <div class="eta-note">假設 8 工時/天 · 純 Codex 自動跑</div>
    </div>
  `
}

function renderBreakdown(byStatus) {
  const rows = [
    { label: 'Ship-Before', ...byStatus.shipBefore, color: 'var(--cta)' },
    { label: 'Beta+1', ...byStatus.beta1, color: 'var(--warning)' },
    { label: 'Backlog', ...byStatus.backlog, color: 'var(--iron)' },
    { label: 'QA (R118)', ...byStatus.qa, color: 'var(--positive)' },
    { label: 'Ops (R118)', ...byStatus.ops, color: 'var(--hot)' },
  ]
  return `
    <div class="breakdown">
      ${rows.map(r => `
        <div class="row">
          <span class="dot" style="background:${r.color}"></span>
          <span class="label">${r.label}</span>
          <span class="tally">${r.done}/${r.total}</span>
          <span class="hours">${r.doneEstHours || 0}/${r.totalEstHours}h</span>
        </div>
      `).join('')}
    </div>
  `
}

function renderVelocityNote(velocity, lastAt) {
  const ago = timeAgo(lastAt)
  return `
    <div class="velocity">
      <div>velocity: <strong>${velocity}h/day</strong></div>
      <div>last updated <strong>${ago}</strong></div>
    </div>
  `
}

function timeAgo(iso) {
  const diffMs = Date.now() - new Date(iso).getTime()
  const mins = Math.floor(diffMs / 60000)
  if (mins < 1) return '剛剛'
  if (mins < 60) return `${mins} 分鐘前`
  const hrs = Math.floor(mins / 60)
  if (hrs < 24) return `${hrs} 小時前`
  return `${Math.floor(hrs / 24)} 天前`
}
```

