### B. `agent-bridge-standalone/server.mjs` 加 PIN 驗

新增 middleware 或 route：
```js
const DASHBOARD_PIN = String(process.env.BRIDGE_DASHBOARD_PIN || '').trim()

app.post('/dashboard/login', (req, res) => {
  const { pin } = req.body || {}
  if (!DASHBOARD_PIN) {
    return res.status(500).json({ error: 'PIN not configured' })
  }
  if (String(pin).trim() !== DASHBOARD_PIN) {
    return res.status(401).json({ ok: false })
  }
  // 發 signed token · 前端存 localStorage · 後續 request 帶 Bearer
  const token = generateSimpleToken() // can use jwt or signed uuid
  return res.json({ ok: true, token, expiresInMs: 1000 * 60 * 60 * 24 * 30 })
})

// 所有 protected dashboard routes (任何 send-message / task-trigger 類) 加 middleware
function requireDashboardAuth(req, res, next) {
  const token = (req.headers.authorization || '').replace('Bearer ', '').trim()
  if (!verifyDashboardToken(token)) {
    return res.status(401).json({ error: 'unauthorized · re-login with PIN' })
  }
  next()
}
```

簡單 token 產生（不裝 jwt 也可以）：
- `token = sha256(PIN + issued_at + random_nonce)` 存 Map<token, expiry> 記憶體
- 或用 `crypto.randomBytes(32).toString('hex')` 存 Map
- 重啟清除（30 天 expiry 夠了）

