<body>
  <main class="card">
    <h1>Agent Bridge · 解鎖</h1>
    <input id="pin" type="password" inputmode="numeric" maxlength="4" pattern="[0-9]{4}" autofocus>
    <br>
    <button id="submit">進入</button>
    <div id="err" class="err"></div>
  </main>
  <script>
    const pinInput = document.getElementById('pin')
    const btn = document.getElementById('submit')
    const err = document.getElementById('err')

    async function submit() {
      const pin = pinInput.value
      if (!/^\d{4}$/.test(pin)) { err.textContent = 'PIN 需 4 位數字'; return }
      const res = await fetch('/dashboard/login', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ pin })
      })
      if (!res.ok) { err.textContent = 'PIN 錯誤'; pinInput.value = ''; return }
      const { token } = await res.json()
      localStorage.setItem('dashboard_token', token)
      localStorage.setItem('dashboard_token_at', Date.now())
      location.href = '/'
    }

    btn.addEventListener('click', submit)
    pinInput.addEventListener('keydown', e => { if (e.key === 'Enter') submit() })
  </script>
</body>
</html>
```

`index.html`（dashboard 主頁）開頭加 auth check：
```js
const token = localStorage.getItem('dashboard_token')
if (!token) { location.href = '/login.html'; }
// 所有 fetch 包 helper 加 Authorization header
async function apiFetch(url, opts = {}) {
  const headers = { ...(opts.headers || {}), Authorization: 'Bearer ' + localStorage.getItem('dashboard_token') }
  return fetch(url, { ...opts, headers })
}
// 401 → 回 login page
```

